import{_ as a,o as e,c as i,ak as l}from"./chunks/framework.oFDsBAuP.js";const u=JSON.parse('{"title":"其他工具配置接入","description":"通过令牌管理导入常见工具配置","frontmatter":{"title":"其他工具配置接入","description":"通过令牌管理导入常见工具配置"},"headers":[],"relativePath":"tools/other-tools.md","filePath":"tools/other-tools.md"}'),o={name:"tools/other-tools.md"};function s(d,t,r,h,n,c){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="其他工具配置接入" tabindex="-1">其他工具配置接入 <a class="header-anchor" href="#其他工具配置接入" aria-label="Permalink to &quot;其他工具配置接入&quot;">​</a></h1><p>如果你使用 Cherry Studio、AionUI、流畅阅读、DeepChat、Lobe Chat、AI as Workspace、AMA 问天、OpenCat 等工具，建议优先通过 AstraLink（全域星链） 控制台的一键导入功能生成配置。</p><h2 id="推荐方式-导入平台配置" tabindex="-1">推荐方式：导入平台配置 <a class="header-anchor" href="#推荐方式-导入平台配置" aria-label="Permalink to &quot;推荐方式：导入平台配置&quot;">​</a></h2><ol><li>进入 AstraLink（全域星链） 控制台。</li><li>打开「令牌管理」。</li><li>找到要使用的令牌。</li><li>点击「聊天」按钮旁边的下箭头。</li><li>在下拉列表中选择对应导入平台，例如 Cherry Studio、AionUI、DeepChat 或 OpenCat。</li><li>按弹窗提示完成配置导入。</li></ol><p>导入后，打开对应工具检查 API 地址、模型和密钥是否已经自动填入。不同工具的界面名称可能略有差异，但入口都在「聊天」按钮旁的下拉菜单中。</p><h2 id="常见工具" tabindex="-1">常见工具 <a class="header-anchor" href="#常见工具" aria-label="Permalink to &quot;常见工具&quot;">​</a></h2><ul><li>Cherry Studio</li><li>AionUI</li><li>流畅阅读</li><li>CC Switch</li><li>DeepChat</li><li>Lobe Chat 官方示例</li><li>AI as Workspace</li><li>AMA 问天</li><li>OpenCat</li></ul><h2 id="手动配置参考" tabindex="-1">手动配置参考 <a class="header-anchor" href="#手动配置参考" aria-label="Permalink to &quot;手动配置参考&quot;">​</a></h2><p>如果工具不支持一键导入，可按以下通用信息手动填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填写内容</th></tr></thead><tbody><tr><td>API Base URL / 接口地址</td><td><code>https://api.astralink.cc/v1</code></td></tr><tr><td>API Key / 密钥</td><td>令牌管理中复制的 <code>sk-...</code> 密钥</td></tr><tr><td>模型</td><td>按工具支持情况选择可用模型</td></tr></tbody></table><p>部分 Claude 兼容工具可能需要填写网关根地址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.astralink.cc</span></span></code></pre></div><p>如果工具要求 OpenAI 兼容接口，一般填写：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.astralink.cc/v1</span></span></code></pre></div><h2 id="遇到问题" tabindex="-1">遇到问题 <a class="header-anchor" href="#遇到问题" aria-label="Permalink to &quot;遇到问题&quot;">​</a></h2><p>如果有其他配置问题，请加入客服群联系咨询。</p><table tabindex="0"><thead><tr><th>联系方式</th><th>信息</th></tr></thead><tbody><tr><td>QQ 客服群</td><td><code>QQ: 1834327560</code></td></tr></tbody></table><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="./cc-switch.html">cc-switch 配置接入</a></li><li><a href="./codex.html">codex 配置接入</a></li><li><a href="./vscode.html">vs code 配置接入</a></li></ul>',19)])])}const b=a(o,[["render",s]]);export{u as __pageData,b as default};
